class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        def compute_lps(pattern: str) -> List[int]:
            n = len(pattern)
            lps = [0] * n
            length = 0
            i = 1
            while i < n:
                if pattern[i] == pattern[length]:
                    length += 1
                    lps[i] = length
                    i += 1
                elif length != 0:
                    length = lps[length - 1]
                else:
                    lps[i] = 0
                    i += 1
            return lps

        def kmp_search(text: str, pattern: str) -> List[int]:
            n, m = len(text), len(pattern)
            lps = compute_lps(pattern)
            indices = []
            i, j = 0, 0
            while i < n:
                if text[i] == pattern[j]:
                    i += 1
                    j += 1
                if j == m:
                    indices.append(i - j)
                    j = lps[j - 1]
                elif i < n and text[i] != pattern[j]:
                    if j != 0:
                        j = lps[j - 1]
                    else:
                        i += 1
            return indices

        a_indices = kmp_search(s, a)
        b_indices = kmp_search(s, b)
        beautiful = []
        j = 0
        for i in a_indices:
            while j < len(b_indices) and b_indices[j] < i - k:
                j += 1
            if j < len(b_indices) and abs(i - b_indices[j]) <= k:
                beautiful.append(i)
        return beautiful
